import (
	"testing"

	"github.com/iksnae/code-certification/internal/discovery"
)

func TestKnownLanguages_ReturnsSortedUnique(t *testing.T) {
	langs := discovery.KnownLanguages()

	if len(langs) == 0 {
		t.Fatal("KnownLanguages() returned empty slice")
	}

	// Verify sorted
	for i := 1; i < len(langs); i++ {
		if langs[i-1] >= langs[i] {
			t.Errorf("KnownLanguages() not sorted: %q >= %q at positions %d, %d",
				langs[i-1], langs[i], i-1, i)
		}
	}

	// Verify unique
	seen := make(map[string]bool)
	for _, l := range langs {
		if seen[l] {
			t.Errorf("KnownLanguages() has duplicate: %q", l)
		}
		seen[l] = true
	}

	// Verify expected languages are present (spot-check a few key ones)
	expected := map[string]bool{
		"go":      true,
		"ts":      true,
		"js":      true,
		"py":      true,
		"java":    true,
		"c":       true,
		"cpp":     true,
		"erlang":  true,
		"elixir":  true,
		"sql":     true,
		"proto":   true,
		"zig":     true,
	}
	for lang := range expected {
		found := false
		for _, l := range langs {
			if l == lang {
				found = true
				break
			}
		}
		if !found {
			t.Errorf("KnownLanguages() missing expected language: %q", lang)
		}
	}
}

